from dataclasses import dataclass
from typing import Any

@dataclass(frozen=True)
class ToolSpec:
    name: str
    description: str
    high_risk: bool = False          # requires extra validation and possible human approval
    allowed_for_roles: frozenset[str] = frozenset()  # empty = all roles allowed

# Registry: only include tools the agent actually needs
CUSTOMER_SUPPORT_TOOLS: list[ToolSpec] = [
    ToolSpec("search_knowledge_base", "Search the product FAQ", high_risk=False),
    ToolSpec("get_order_status", "Look up an order by ID", high_risk=False),
    ToolSpec("create_refund_request", "Submit a refund", high_risk=True, allowed_for_roles=frozenset({"support_agent"})),
    # NOT included: send_email, execute_sql, run_shell, http_post
]

TOOL_REGISTRY: dict[str, ToolSpec] = {t.name: t for t in CUSTOMER_SUPPORT_TOOLS}

class ToolDispatcher:
    def __init__(self, agent_role: str, tools: list[ToolSpec]):
        self._role = agent_role
        self._specs = {t.name: t for t in tools}

    def dispatch(
        self,
        tool_name: str,
        args: dict[str, Any],
        *,
        human_approved: bool = False,
    ) -> Any:
        spec = self._specs.get(tool_name)
        if spec is None:
            raise PermissionError(
                f"Tool '{tool_name}' is not in the allowed tool set for this agent"
            )
        if spec.allowed_for_roles and self._role not in spec.allowed_for_roles:
            raise PermissionError(
                f"Role '{self._role}' is not authorised to call '{tool_name}'"
            )
        if spec.high_risk and not human_approved:
            raise PermissionError(
                f"Tool '{tool_name}' is high-risk and requires human approval"
            )
        return self._execute(spec, args)

    def _execute(self, spec: ToolSpec, args: dict) -> Any:
        raise NotImplementedError

import re, os
from pathlib import Path

class FileWriteTool:
    ALLOWED_ROOT = Path("/var/agent/workspace")
    ALLOWED_EXTENSIONS = {".txt", ".json", ".csv", ".md"}
    MAX_SIZE_BYTES = 1024 * 1024  # 1 MB

    def __call__(self, path: str, content: str) -> str:
        # Resolve to absolute path and confirm it is inside the allowed root
        target = (self.ALLOWED_ROOT / path).resolve()
        if not str(target).startswith(str(self.ALLOWED_ROOT)):
            raise PermissionError(
                f"Path traversal attempt: {path!r} resolves outside workspace"
            )
        # Extension check
        if target.suffix not in self.ALLOWED_EXTENSIONS:
            raise ValueError(
                f"Extension {target.suffix!r} is not allowed. "
                f"Allowed: {self.ALLOWED_EXTENSIONS}"
            )
        # Size check
        if len(content.encode()) > self.MAX_SIZE_BYTES:
            raise ValueError("Content exceeds maximum allowed size")
        target.parent.mkdir(parents=True, exist_ok=True)
        target.write_text(content)
        return f"Wrote {len(content)} chars to {target.relative_to(self.ALLOWED_ROOT)}"

class SqlQueryTool:
    def __call__(self, conn, query: str, params: tuple = ()) -> list[dict]:
        # Never allow DDL statements
        FORBIDDEN = re.compile(r"^\s*(DROP|CREATE|ALTER|TRUNCATE|GRANT|REVOKE)", re.I)
        if FORBIDDEN.match(query):
            raise PermissionError(f"DDL statements are not allowed: {query[:60]!r}")
        # Always use parameterised queries — never format user data into the SQL
        cursor = conn.cursor()
        cursor.execute(query, params)      # params separate from query string
        return [dict(zip([c[0] for c in cursor.description], row))
                for row in cursor.fetchall()]

import time
from collections import defaultdict
from dataclasses import dataclass, field

@dataclass
class ToolBudget:
    calls_per_minute: int = 20
    calls_per_session: int = 200
    high_risk_calls_per_session: int = 5

class RateLimitedDispatcher:
    def __init__(self, underlying: ToolDispatcher, budget: ToolBudget):
        self._underlying = underlying
        self._budget = budget
        self._call_log: list[float] = []
        self._session_count: int = 0
        self._high_risk_count: int = 0

    def dispatch(self, tool_name: str, args: dict, **kwargs) -> any:
        now = time.monotonic()
        # Per-minute rate limit
        self._call_log = [t for t in self._call_log if now - t < 60]
        if len(self._call_log) >= self._budget.calls_per_minute:
            raise RuntimeError(
                f"Tool rate limit exceeded: {self._budget.calls_per_minute} calls/min"
            )
        # Session cap
        if self._session_count >= self._budget.calls_per_session:
            raise RuntimeError(
                f"Session tool budget exhausted ({self._budget.calls_per_session} calls)"
            )
        # High-risk cap
        spec = self._underlying._specs.get(tool_name)
        if spec and spec.high_risk:
            if self._high_risk_count >= self._budget.high_risk_calls_per_session:
                raise RuntimeError(
                    f"High-risk tool budget exhausted "
                    f"({self._budget.high_risk_calls_per_session} calls)"
                )
            self._high_risk_count += 1

        self._call_log.append(now)
        self._session_count += 1
        return self._underlying.dispatch(tool_name, args, **kwargs)

from dataclasses import dataclass
from enum import Enum, auto

class ApprovalStatus(Enum):
    PENDING  = auto()
    APPROVED = auto()
    REJECTED = auto()

@dataclass
class PendingAction:
    action_id: str
    tool_name: str
    args: dict
    description: str               # human-readable summary for the approver
    status: ApprovalStatus = ApprovalStatus.PENDING
    rejection_reason: str = ""

class HumanApprovalGate:
    """
    Stores pending actions and exposes approval/rejection endpoints.
    In a real deployment these would be backed by a database with TTL.
    """
    def __init__(self):
        self._pending: dict[str, PendingAction] = {}

    def submit(self, action: PendingAction) -> str:
        self._pending[action.action_id] = action
        # In production: send notification to human reviewer (Slack, email, UI)
        _notify_human_reviewer(action)
        return action.action_id

    def approve(self, action_id: str) -> None:
        action = self._pending[action_id]
        action.status = ApprovalStatus.APPROVED

    def reject(self, action_id: str, reason: str) -> None:
        action = self._pending[action_id]
        action.status = ApprovalStatus.REJECTED
        action.rejection_reason = reason

    def get_approved(self, action_id: str) -> PendingAction:
        action = self._pending.get(action_id)
        if action is None:
            raise KeyError(action_id)
        if action.status != ApprovalStatus.APPROVED:
            raise PermissionError(
                f"Action {action_id} not approved (status: {action.status.name})"
            )
        del self._pending[action_id]
        return action
